noncompliant:
// Noncompliant: Jumping into complex constructs
void example() {
    goto label;

    for (int i = 0; i < 10; i++) {
        if (i == 5) {
            label: // Jump into loop body
            doSomething();
        }
    }
}

// Noncompliant: Switch case jumping into try block
void badSwitch(int value) {
    switch (value) {
        case 1:
            try {
        case 2: // Jump into try block
                processValue();
            } catch (...) {
                handleError();
            }
            break;
    }
}

compliant:
// Compliant: Structured control flow
void example() {
    for (int i = 0; i < 10; i++) {
        if (i == 5) {
            doSomething();
            break; // Clean exit
        }
    }
}

// Compliant: Switch entirely within try block
void goodSwitch(int value) {
    try {
        switch (value) {
            case 1:
                processValue1();
                break;
            case 2:
                processValue2();
                break;
        }
    } catch (...) {
        handleError();
    }
}
